#!/intel/tpvalidation/engtools/tptools/mtl/pyston/pyston2.3.4/bin/pyston
"""
Unit test for missing_ports.py
"""
from setenv_unittest import UT_DIR, UT_DIR_REPO, ROOT_ENV, EXIST_PDX_I_DRIVE     # must be first import for unittests
from qgates.missing_ports import *
from gadget.ut import TestCase, unittest, is_ut_option, MockVar
from gadget.files import TempDir, File
from os.path import basename
from unittest.mock import Mock


class TestMissingPorts(TestCase):

    def test_basic_pass(self):
        # real small program full flow - pass case - no xml or no json
        tpobj = TestProgram(f'{UT_DIR_REPO}/Simple3a/POR_TP/TGLH81/EnvironmentFile.env').init()
        obj = MissingPorts(tpobj)
        obj.main()
        self.assertEqual(obj.result, [])

    def test_basic_fail(self):
        tpobj = TestProgram(f'{UT_DIR_REPO}/Simple3_missingports/POR_TP/TGLH81/EnvironmentFile.env').init()
        obj = MissingPorts(tpobj)
        obj.main()
        pprint(obj.result)
        expect = [{'id': 211,
                   'message': 'Input json file vs mtpl file mismatch: Port3 defined in json '
                   'file but Not defined in mtpl file. TestName: ARR/CCA, ConfigFile: '
                   'CLASS_P28G1_dlvrcalc_dac_chk.json ConfigSet: DAC_CHK_15C',
                   'module': 'ARR'}]
        self.assertEqual(obj.result, expect)

    @unittest.skipIf(not EXIST_PDX_I_DRIVE, r'This unittest needs pdx I:\ drive mapped')
    def test_main_xml(self):
        tpobj = TestProgram(f'{UT_DIR}/MTLXXXXXXX37B0ASXXX/POR_TP/Class_MTL_P28/EnvironmentFile.env')

        # case1 - xml pass case
        def fake_read_xml_failport(filename, set, *ignore):
            self.assertEqual(basename(filename), 'file.xml')
            self.assertEqual(set, 'some_setting')

        ports = {999: 'abc'}
        data = [('ARR', 'testabc', {'config_file': 'file.xml',
                                    'levels': 'blah',
                                    'config_set': 'some_setting'},
                 ports)]
        with MockVar(tpobj.mtpl, "iter_flows", Mock(return_value=data)):
            obj = MissingPorts(tpobj)
            with MockVar(obj, "read_xml_failport", fake_read_xml_failport):
                obj.main()

        # case2 - xml with ~
        def fake_read_xml_failport(filename, set, *ignore):
            self.fail("read_xml_failport should not be called")

        ports = {999: 'abc'}
        data = [('ARR', 'testabc', {'config_file': '~/file.xml', 'config_set': 'some_setting'}, ports)]
        with MockVar(tpobj.mtpl, "iter_flows", Mock(return_value=data)):
            obj = MissingPorts(tpobj)
            with MockVar(MissingPorts, "read_xml_failport", fake_read_xml_failport):
                obj.main()

        # case3 - none found
        def fake_read_xml_failport(filename, set, *ignore):
            self.fail("read_xml_failport should not be called")

        ports = {999: 'abc'}
        data = [('ARR', 'testabc', {'config_set': 'some_setting'}, ports)]
        with MockVar(tpobj.mtpl, "iter_flows", Mock(return_value=data)):
            obj = MissingPorts(tpobj)
            with MockVar(MissingPorts, "read_xml_failport", fake_read_xml_failport):
                obj.main()

    @unittest.skipIf(not EXIST_PDX_I_DRIVE, r'This unittest needs pdx I:\ drive mapped')
    def test_main_json(self):
        tpobj = TestProgram(f'{UT_DIR}/MTLXXXXXXX37B0ASXXX/POR_TP/Class_MTL_P28/EnvironmentFile.env')

        # case1 - pass case
        # Test Strategy: Mock iter_flows to the data we want,
        #    Then create a "fake" read_json_failport and check the filename and set if it is correct
        def fake_read_json_failport(filename, set, json_object, *ignore):
            self.assertEqual(basename(filename), 'file.json')
            self.assertEqual(set, 'some_setting')
            self.assertEqual(json_object, {"data": 1})

        ports = {999: 'abc'}
        data = [('ARR', 'testabc', {'ConfigFile': 'file.json',
                                    'levels': 'ignore_this',
                                    'ConfigSet': 'some_setting'}, ports)]
        with TempDir(name=True, chdir=True) as tdir:
            File('file.json').touch('{ "data": 1}')
            with MockVar(tpobj.mtpl, "iter_flows", Mock(return_value=data)):
                obj = MissingPorts(tpobj)
                tpobj.tpldir = tdir
                with MockVar(obj, "read_json_failport", fake_read_json_failport):
                    obj.main()

        # case2 - fail json case
        def fake_read_json_failport(filename, set, json_object, *ignore):
            self.fail("read_xml_failport should not be called")

        ports = {999: 'abc'}
        data = [('ARR', 'testabc', {'ConfigFile': 'file.json', 'ConfigSet': 'some_setting'}, ports)]
        with TempDir(name=True, chdir=True) as tdir:
            File('file.json').touch("{ 'data': 1},")    # invalid
            with MockVar(tpobj.mtpl, "iter_flows", Mock(return_value=data)):
                obj = MissingPorts(tpobj)
                tpobj.tpldir = tdir
                with MockVar(MissingPorts, "read_json_failport", fake_read_json_failport):
                    obj.main()

        # case3 - no configfile
        def fake_read_json_failport(filename, set, json_object, *ignore):
            self.fail("read_xml_failport should not be called")

        ports = {999: 'abc'}
        data = [('ARR', 'testabc', {'ConfigSet': 'some_setting'}, ports)]
        with TempDir(name=True, chdir=True) as tdir:
            File('file.json').touch('{ "data": 1}')
            with MockVar(tpobj.mtpl, "iter_flows", Mock(return_value=data)):
                obj = MissingPorts(tpobj)
                tpobj.tpldir = tdir
                with MockVar(MissingPorts, "read_json_failport", fake_read_json_failport):
                    obj.main()

    def test_fail_xml(self):
        ff = f'{UT_DIR_REPO}/xml_ut/CLASS_P68G2_ANAMEAS_mtl_dlvr_Iccmax.fail.xml'
        obj = MissingPorts(None)
        obj.read_xml_failport(ff, 'ANAPRB', {}, 'ARR', {})
        msg = 'Input xml for ARR has error: mismatched tag: line 2569, column 22; Fix CLASS_P68G2_ANAMEAS_mtl_dlvr_Iccmax.fail.xml'
        self.assertEqual(obj.result, [{'id': 213, 'message': msg, 'module': 'ARR'}])

